   653	// renderHierarchyJSON writes the aggregate machine-readable document: one
   654	// entry per emit scope plus the run-wide exit code. The embedded summary uses
   655	// the report.Summary JSON tags (the same shape report.MarshalJSON emits).
   656	// notice is additive (omitempty) and set only on zero-emit runs, so existing
   657	// schema_version 1 consumers are unaffected.
   658	func renderHierarchyJSON(w io.Writer, outcomes []scopeOutcome, notice string) error {
   659		scopes := make([]hierarchyScopeJSON, 0, len(outcomes))
   660		for _, o := range outcomes {
   661			entry := hierarchyScopeJSON{
   662				Root:     o.Scope.Root,
   663				Level:    o.Scope.Level.String(),
   664				Warnings: o.Warnings,
   665			}
   666			if o.Err != nil {
   667				entry.Error = o.Err.Error()
   668			} else {
   669				// Embed the per-scope summary raw: the aggregate is marshaled
   670				// below via json.Marshal(doc), which uses report.Summary's struct
   671				// tags directly rather than report.MarshalJSON. This is
   672				// intentional. The aggregate document carries its own top-level
   673				// schema_version, and each embedded summary's JSON matches the
   674				// standalone report shape minus that version wrapper (targets is
   675				// populated by Summarize, not by the marshaler). Per-scope
   676				// summaries deliberately do not repeat schema_version.
   677				s := o.Summary
   678				entry.Summary = &s
   679			}
   680			scopes = append(scopes, entry)
   681		}
   682		doc := struct {
   683			SchemaVersion int                  `json:"schema_version"`
   684			Scopes        []hierarchyScopeJSON `json:"scopes"`
   685			Notice        string               `json:"notice,omitempty"`
   686			ExitCode      int                  `json:"exit_code"`
   687		}{
   688			SchemaVersion: 1,
   689			Scopes:        scopes,
   690			Notice:        notice,
   691			ExitCode:      hierarchyExitCode(outcomes),
   692		}
   693		data, err := json.Marshal(doc)
   694		if err != nil {
   695			return fmt.Errorf("cli: marshal hierarchy json: %w", err)
   696		}
   697		_, err = fmt.Fprintln(w, string(data))
   698		return err
   699	}
